SELECT report_name, report_id
FROM network_reports
WHERE report_type = 'performance' AND tower_id = 1;

SELECT QUOTE(tower_name) 
FROM cell_towers 
WHERE tower_name = 'Tower B' AND installation_date = '2020-02-01';

SELECT towers.tower_name, network_reports.report_name, network_reports.report_date, network_reports.report_type
FROM towers
JOIN network_reports ON towers.tower_id = network_reports.tower_id;

SELECT tower_id, AVG(rsrp) AS avg_rsrp, AVG(sinr) AS avg_sinr, AVG(rss) AS avg_rss, AVG(rssi) AS avg_rssi
FROM signal_quality JOIN environmental_data ON signal_quality.data_id = environmental_data.data_id
GROUP BY tower_id;

SELECT report_type, COUNT(*) AS num_reports
FROM network_reports
GROUP BY report_type;

SELECT *
FROM cells
INNER JOIN towers ON cells.tower_id = towers.tower_id;

SELECT t.tower_name, ed.x, ed.y, ed.altitude, ed.building_height, ed.clutter_index, ed.temperature, ed.humidity, ed.weather_conditions
FROM towers t
JOIN environmental_data ed ON t.tower_id = ed.tower_id;

SELECT tower_id, tower_name, cell_index, cell_x, cell_y
FROM cell_towers
ORDER BY cell_index DESC;

SELECT city, COUNT(DISTINCT tower_id) AS unique_towers
FROM towers
GROUP BY city;

SELECT tower_name, height, cell_index
FROM cell_towers
ORDER BY height DESC;

SELECT AVG(CAST(rsrp_data AS REAL)) AS average_rsrp
FROM network_reports
WHERE tower_id = 1;

SELECT ct.cell_x, ct.cell_y, ed.x, ed.y
FROM cell_towers ct
JOIN environmental_data ed ON ct.tower_id = ed.tower_id;

SELECT COUNT(*) AS Total_Towers, MAX(height) AS Maximum_Height
FROM cell_towers
WHERE tower_name = 'Tower A';

SELECT * 
FROM maintenances 
WHERE tower_id = 1;

SELECT COUNT(DISTINCT tower_id)
FROM cell_towers
WHERE installation_date > '2020-01-01';

SELECT data_id, rssi
FROM signal_quality
ORDER BY data_id;
